head.script:
scwin.rowM = 0; //반출입정정 신고정보 RowPosition
scwin.rowR = 0; //Row변경시 이전 Row

scwin.onpageload = function() {
	const codeOptions = [
        { grpCd : "OP197", compID : "acb_crryinoutClsCd,gr_ContainerBulkInfo:crryinoutClsCd" }, //반출입구분
        { grpCd : "OP135", compID : "gr_ContainerBulkInfo:divsCrryinoutClsCd" }, // 그리드 분할반출입구분
        { grpCd : "OP133", compID : "gr_ContainerBulkInfo:crryinoutPatternCd" }, // 그리드 반출입유형
        { grpCd : "OP132", compID : "gr_ContainerBulkInfo:crryinoutAccdPatternCd" }, // 그리드 반출입사고유형

        { grpCd : "OP138", compID : "gr_CDMainInfo:mainMainClsMark" }, // 그리드 구분번호

    ];

    $c.data.setCommonCode(codeOptions);

    $c.gus.cfDisableObjects([udc_bottomGrdBtnCDMainInfo,udc_bottomGrdBtnCDMainRegularityTaxInfo,btn_transfer,btn_save]);

    acb_wrkClsCd.focus();

    scwin.f_gridFormatChange("B");

    //임시
    // ed_mrn.setValue("12L37KA1938");
    // ed_msn.setValue("1");
    // ed_hsn.setValue("500");

};

//-------------------------------------------------------------------------
// Grid Format 변경
//------------------------------------------------------------------------- 
scwin.f_gridFormatChange = function(argGubun) {

    if (argGubun == "C") { // 컨테이너
        ed_cntrNo.setMandatory(true);
        ed_cntrNo.setDisabled(false);
        cb_title.setValue("컨테이너 세관신고 현황");

        gr_ContainerBulkInfo.setColumnReadOnly("분할반출입구분", true);

        gr_ContainerBulkInfo.getCellInfo("crryinoutPatternCd").options.selectedData = false;
        gr_ContainerBulkInfo.getCellInfo("crryinoutAccdPatternCd").options.selectedData = false;
        gr_ContainerBulkInfo.getCellInfo("crryinoutPatternCd").options.displayMode = "value delim label";
        gr_ContainerBulkInfo.getCellInfo("crryinoutAccdPatternCd").options.displayMode = "value delim label";

        gr_CDMainInfo.setColumnVisible("mrn", false);
        gr_CDMainInfo.setColumnVisible("msn", false);
        gr_CDMainInfo.setColumnVisible("hsn", false);
        gr_CDMainInfo.setColumnVisible("cntrNo", true);

        gr_CDMainRegularityTaxInfo.setColumnVisible("addBl", true);

        cntrLableReq.show();
        cntrLable.hide();

    } else if (argGubun == "B") { // 벌크

        ed_cntrNo.setMandatory("false");
        ed_cntrNo.setValue("");
        ed_cntrNo.setDisabled(true)
        $c.gus.cfDisableObjects([ed_cntrNo]);
        cb_title.setValue("벌크 세관신고 현황");
        gr_ContainerBulkInfo.getCellInfo("crryinoutPatternCd").options.selectedData = true;
        gr_ContainerBulkInfo.getCellInfo("crryinoutAccdPatternCd").options.selectedData = true;
        gr_ContainerBulkInfo.getCellInfo("crryinoutPatternCd").options.displayMode = "label";
        gr_ContainerBulkInfo.getCellInfo("crryinoutAccdPatternCd").options.displayMode = "label";
        gr_CDMainInfo.setColumnVisible("mrn", true);
        gr_CDMainInfo.setColumnVisible("msn", true);
        gr_CDMainInfo.setColumnVisible("hsn", true);
        gr_CDMainInfo.setColumnVisible("cntrNo", false);

        gr_CDMainRegularityTaxInfo.setColumnVisible("addBl", false);

        cntrLableReq.hide();
        cntrLable.show();

    } else {
        $c.gus.cfAlertMsg("작업구분을 선택하십시오.");
    }
    ///$c.gus.cfRefreshMandSign();
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_condition, null);
    acb_wrkClsCd.setSelectedIndex(0);
    acb_wrkClsCd.focus();
};


//-------------------------------------------------------------------------
// 조회
//------------------------------------------------------------------------- 
scwin.f_Retrieve = async function() {

    if (acb_wrkClsCd.getValue() == 'B') {
        if (! await $c.gus.cfValidate([ed_mrn])) {	// MRN
            return;
        }
    } else if (acb_wrkClsCd.getValue() == 'C') {
        if (ed_cntrNo.getValue() == "" && ed_mrn.getValue() == "") {	// 컨테이너번호, MRN
            $c.gus.cfAlertMsg("컨테이너번호나 화물관리번호(MRN)중 한가지 조건은 입력하십시오.");
            return;
        }
    }

     $c.sbm.execute(sbm_retrieve);

};



scwin.f_Retrieve1 = function (row) {

    dma_condition1.set("wrkClsCd", ds_ContainerBulkInfo.getCellData(row, "wrkClsCd"));
    dma_condition1.set("crryinoutClsCd", ds_ContainerBulkInfo.getCellData(row, "crryinoutClsCd"));
    dma_condition1.set("wrkPlCd", ds_ContainerBulkInfo.getCellData(row, "wrkPlCd"));
    dma_condition1.set("cntrNo", ds_ContainerBulkInfo.getCellData(row, "cntrNo"));
    dma_condition1.set("mrn", ds_ContainerBulkInfo.getCellData(row, "mrn"));
    dma_condition1.set("msn", ds_ContainerBulkInfo.getCellData(row, "msn"));
    dma_condition1.set("hsn", ds_ContainerBulkInfo.getCellData(row, "hsn"));
    dma_condition1.set("divsCrryinoutDeg", ds_ContainerBulkInfo.getCellData(row, "divsCrryinoutDeg"));

    $c.sbm.execute(sbm_retrieve1);
};


scwin.f_Retrieve2 = function (row) {

    var rowIndex = row;
    if(row == "" || row == undefined){
        rowIndex = "0";
    } 
    if (ds_CDMainInfo.getRowCount() > 0) {
        dma_condition2.set("wrkClsCd", ds_CDMainInfo.getCellData(rowIndex, "wrkClsCd"));
        dma_condition2.set("crryinoutClsCd", ds_CDMainInfo.getCellData(rowIndex, "crryinoutClsCd"));
        dma_condition2.set("wrkPlCd", ds_CDMainInfo.getCellData(rowIndex, "wrkPlCd"));
        dma_condition2.set("cntrNo", ds_CDMainInfo.getCellData(rowIndex, "cntrNo"));
        dma_condition2.set("mrn", ds_CDMainInfo.getCellData(rowIndex, "mrn"));
        dma_condition2.set("msn", ds_CDMainInfo.getCellData(rowIndex, "msn"));
        dma_condition2.set("hsn", ds_CDMainInfo.getCellData(rowIndex, "hsn"));
        dma_condition2.set("divsCrryinoutDeg", ds_CDMainInfo.getCellData(rowIndex, "divsCrryinoutDeg"));
        dma_condition2.set("mainMainAppDeg", ds_CDMainInfo.getCellData(rowIndex, "mainMainAppDeg"));

    } else {
        dma_condition2.set("wrkClsCd", "");
        dma_condition2.set("crryinoutClsCd","");
        dma_condition2.set("wrkPlCd", "");
        dma_condition2.set("cntrNo", "");
        dma_condition2.set("mrn", "");
        dma_condition2.set("msn", "");
        dma_condition2.set("hsn", "");
        dma_condition2.set("divsCrryinoutDeg", "");
        dma_condition2.set("mainMainAppDeg", "");

        dma_condition2.set("wrkClsCd", ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "wrkClsCd"));
    }

    $c.sbm.execute(sbm_retrieve2);
};


//저장
scwin.f_Save = async function() {

  scwin.rowM = ds_CDMainInfo.getRowPosition(); //저장당시 RowPosition으로 되돌리기 위함
  if (ds_CDMainInfo.getRowStatus(scwin.rowM) == "D") { //저장당시 RowPosition의 상태가 삭제면 RowPosition = 1로 변경
    scwin.rowM = 1;
  }

  if (ds_CDMainInfo.getModifiedIndex().length == 0 && ds_CDMainRegularityTaxInfo.getModifiedIndex().length == 0) {
    $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["반출입정정 신고정보 및 신고정보상세"]); // "@은(는) 변경된 사항이 없습니다."
    return;
  }

  let ret = await $c.gus.cfValidate([gr_CDMainInfo]);

  if (ds_CDMainInfo.getModifiedIndex().length != 0) {
    if (!ret) {
      return;
    }
  }

  if (ds_CDMainRegularityTaxInfo.getModifiedIndex().length != 0) {
    var itemG = 0; //반입개수
    var itemK = 0; //사고유형부호
    var itemL = 0; //사고개수
    var itemH = 0; //반입중량
    var itemM = 0; //사고중량

    for (var i = 0; i < ds_CDMainRegularityTaxInfo.getRowCount(); i++) {
      if (ds_CDMainRegularityTaxInfo.getRowStatus(i) != "D") {
        if (ds_CDMainRegularityTaxInfo.getCellData(i, "wrkClsCd") == 'C') {
          if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainItem") == '0'
            && ds_CDMainRegularityTaxInfo.getCellData(i, "addBl") == "") {
            $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["B/L정보"]); // "@은(는) 필수 입력 항목입니다."
            ds_CDMainRegularityTaxInfo.setRowPosition(i);
            ds_CDMainRegularityTaxInfo.setFocusedCell(i, "addBl", true);
            ds_CDMainRegularityTaxInfo.focus();            
            return;
          }
        } else {

          if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainItem") == "") {
            $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["정정항목"]); // "@은(는) 필수 입력 항목입니다."
            ds_CDMainRegularityTaxInfo.setRowPosition(i);
            gr_CDMainInfo.setFocusedCell(i, "mainMainItem", true);
            gr_CDMainInfo.focus();                  
            return;
          }

          if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainItem") != "R") {
            if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainBfCont") == "") {
              $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["정정전내역"]); // "@은(는) 필수 입력 항목입니다."
              ds_CDMainRegularityTaxInfo.setRowPosition(i);

              ds_CDMainRegularityTaxInfo.setFocusedCell(i, "mainMainBfCont", true);
              ds_CDMainRegularityTaxInfo.focus();     
              return;
            }
          }

          if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainAfCont") == "") {
            $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["정정후내역"]); // "@은(는) 필수 입력 항목입니다."
            ds_CDMainRegularityTaxInfo.setRowPosition(i);
              ds_CDMainRegularityTaxInfo.setFocusedCell(i, "mainMainAfCont", true);
              ds_CDMainRegularityTaxInfo.focus();     
            return;
          }
        }

        if (ds_CDMainRegularityTaxInfo.getCellData(i, "wrkClsCd") == 'B'
          && ds_CDMainRegularityTaxInfo.getCellData(i, "crryinoutClsCd") == 'I') {
          if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainItem") == 'G') {
            itemG = 1;
          }

          if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainItem") == 'K') {
            itemK = 1;
          }

          if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainItem") == 'L') {
            itemL = 1;
          }

          if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainItem") == 'H') {
            itemH = 1;
          }

          if (ds_CDMainRegularityTaxInfo.getCellData(i, "mainMainItem") == 'M') {
            itemM = 1;
          }
        }
      }
    }

    if (itemG == 1 && itemK == 0
      || itemL == 1 && itemK == 0) {
      $c.gus.cfAlertMsg("정정항목중 반입개수/사고유형부호/사고개수는 한쌍으로 등록되어야 합니다.\n사고유형부호를 입력하십시오.");
      return;
    }

    if (itemG == 1 && itemL == 0) {
      $c.gus.cfAlertMsg("정정항목중 반입개수/사고유형부호/사고개수는 한쌍으로 등록되어야 합니다.\n사고개수를 입력하십시오.");
      return;
    }

    if (itemL == 1 && itemG == 0) {
      $c.gus.cfAlertMsg("정정항목중 반입개수/사고유형부호/사고개수는 한쌍으로 등록되어야 합니다.\n반입개수를 입력하십시오.");
      return;
    }

    if (itemH == 1 && itemK == 0
      || itemM == 1 && itemK == 0) {
      $c.gus.cfAlertMsg("정정항목중 반입중량/사고유형부호/사고중량은 한쌍으로 등록되어야 합니다.\n사고유형부호를 입력하십시오.");
      return;
    }

    if (itemH == 1 && itemM == 0) {
      $c.gus.cfAlertMsg("정정항목중 반입중량/사고유형부호/사고중량은 한쌍으로 등록되어야 합니다.\n사고중량을 입력하십시오.");
      return;
    }

    if (itemM == 1 && itemH == 0) {
      $c.gus.cfAlertMsg("정정항목중 반입중량/사고유형부호/사고중량은 한쌍으로 등록되어야 합니다.\n반입중량을 입력하십시오.");
      return;
    }

    if (itemK == 1 && (itemG == 0 && itemH == 0)) {
      if (itemL == 1) {
        $c.gus.cfAlertMsg("정정항목중 반입개수/사고유형부호/사고개수는 한쌍으로 등록되어야 합니다.\n반입개수를 입력하십시오.");
        return;

      } else if (itemL == 1) {
        $c.gus.cfAlertMsg("정정항목중 반입중량/사고유형부호/사고중량은 한쌍으로 등록되어야 합니다.\n반입중량을 입력하십시오.");
        return;

      } else {
        $c.gus.cfAlertMsg("정정항목중 반입개수/사고유형부호/사고개수,\n반입중량/사고유형부호/사고중량은 한쌍으로 등록되어야 합니다.\n반입개수 또는 반입중량을 입력하십시오.");
        return;

      }
    }

    if (itemK == 1 && (itemL == 0 && itemH == 0)) {
      if (itemG == 1) {
        $c.gus.cfAlertMsg("정정항목중 반입개수/사고유형부호/사고개수는 한쌍으로 등록되어야 합니다.\n사고개수를 입력하십시오.");
        return;

      } else if (itemH == 1) {
        $c.gus.cfAlertMsg("정정항목중 반입중량/사고유형부호/사고중량은 한쌍으로 등록되어야 합니다.\n사고중량을 입력하십시오.");
        return;

      } else {
        $c.gus.cfAlertMsg("정정항목중 반입개수/사고유형부호/사고개수,\n반입중량/사고유형부호/사고중량은 한쌍으로 등록되어야 합니다.\n사고개수 또는 사고중량을 입력하십시오.");
        return;

      }
    }
  }

  if (await $c.win.confirm(MSG_CM_CRM_001)) {
    $c.sbm.execute(sbm_save);
  }
};


//전송
scwin.f_Sand = async function() {

  if (ds_CDMainInfo.getModifiedIndex().length) {
    $c.gus.cfAlertMsg(MSG_CM_ERR_042, ["반출입정정 신고정보", "전송"]); //"@은(는) 변경된 사항이 있습니다. \n변경사항을 저장 후 @을(를) 수행하십시오."
    return;
  }

  var j = 0;
  for (var i = 0; i <= ds_CDMainInfo.getRowCount(); i++) {
    if (ds_CDMainInfo.getCellData(i, "sndClsCd") == "3") {
      ds_CDMainInfo.setCellData(i, "sndClsCd", 0);
      j++;
    }
  }
  if (j == 0) {
    await $c.gus.cfAlertMsg("전송할 건이 없습니다.");
    return;
  }

  if (await $c.win.confirm("전송하시겠습니까?")) {
    $c.sbm.execute(sbm_save1);
  }
};


//행추가
scwin.f_Addrow1 = function(argGubun) {

    var row = ds_ContainerBulkInfo.getRowPosition();
    if (ds_ContainerBulkInfo.getCellData(row, "sndClsNm") != "접수") {
      $c.gus.cfAlertMsg("해당 세관신고정보의 전송구분이 접수인 상태만 행추가를 할 수 있습니다.");
      return;
    }

    ds_CDMainInfo.insertRow();
    var row1 = ds_CDMainInfo.getRowPosition();

    ds_CDMainInfo.setCellData(row1, "wrkClsCd", ds_ContainerBulkInfo.getCellData(row, "wrkClsCd"));
    ds_CDMainInfo.setCellData(row1, "crryinoutClsCd", ds_ContainerBulkInfo.getCellData(row, "crryinoutClsCd"));
    ds_CDMainInfo.setCellData(row1, "wrkPlCd", ds_ContainerBulkInfo.getCellData(row, "wrkPlCd"));
    ds_CDMainInfo.setCellData(row1, "cntrNo", ds_ContainerBulkInfo.getCellData(row, "cntrNo"));
    ds_CDMainInfo.setCellData(row1, "mrn", ds_ContainerBulkInfo.getCellData(row, "mrn"));
    ds_CDMainInfo.setCellData(row1, "msn", ds_ContainerBulkInfo.getCellData(row, "msn"));
    ds_CDMainInfo.setCellData(row1, "hsn", ds_ContainerBulkInfo.getCellData(row, "hsn"));
    ds_CDMainInfo.setCellData(row1, "divsCrryinoutDeg", ds_ContainerBulkInfo.getCellData(row, "divsCrryinoutDeg"));
    ds_CDMainInfo.setCellData(row1, "sndClsCd", "3");

    gr_CDMainInfo.setFocusedCell(row1, "mainMainClsMark", true);
    gr_CDMainInfo.focus();

};

scwin.f_cancel = function(){

   if(ds_CDMainInfo.getRowStatus(ds_CDMainInfo.getRowPosition())=="C"){  				
        ds_CDMainInfo.removeRow(ds_CDMainInfo.getRowPosition())	;	
    } else {
        ds_CDMainInfo.undoRow(ds_CDMainInfo.getRowPosition());
    };

}
scwin.f_cancel2 = function(){

      if(ds_CDMainRegularityTaxInfo.getRowStatus(ds_CDMainRegularityTaxInfo.getRowPosition())=="C"){  				
        ds_CDMainRegularityTaxInfo.removeRow(ds_CDMainRegularityTaxInfo.getRowPosition())	;	
    } else {
        ds_CDMainRegularityTaxInfo.undoRow(ds_CDMainRegularityTaxInfo.getRowPosition());
    };

}

