//행삭제
scwin.f_Delete1 = function(argGubun) {

  var row = ds_ContainerBulkInfo.getRowPosition();
  var row1 = ds_CDMainInfo.getRowPosition();
  if (ds_CDMainInfo.getCellData(row1, "sndClsCd") != 3) {
    $c.gus.cfAlertMsg("해당 반출입정정 신고정보의 전송구분이 미전송인 상태만 행삭제를 할 수 있습니다.");
    return;
  }

  if (ds_ContainerBulkInfo.getCellData(row, "sndClsNm") != "접수") {
    $c.gus.cfAlertMsg("해당 세관신고정보의 전송구분이 접수인 상태만 행삭제를 할 수 있습니다.");
    return;
  }
  if(ds_CDMainInfo.getRowStatus(row1) == "C" ){
    ds_CDMainInfo.removeRow(row1);

  } else {
    ds_CDMainInfo.deleteRow(row1);
    ds_CDMainRegularityTaxInfo.removeAll();

  }

};


