  }

};

// 오류 상세내역 조회 팝업
scwin.f_errorPopUp = function(row) {
    var declarAdmitClsCd = '';

    //  문서종류 코드 상세 셋팅 - 20180817
    if (ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "wrkClsCd") == 'C'
        && ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "crryinoutClsCd") == 'I') {
        declarAdmitClsCd = '5LF';
    } else if (ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "wrkClsCd") == 'C'
        && ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "crryinoutClsCd") == 'O') {
        declarAdmitClsCd = '5LL';
    } else if (ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "wrkClsCd") == 'B'
        && ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "crryinoutClsCd") == 'I') {
        declarAdmitClsCd = '5LC';
    } else if (ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "wrkClsCd") == 'B'
        && ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "crryinoutClsCd") == 'O') {
        declarAdmitClsCd = '5LD';
    }
    var declarNo = ds_ContainerBulkInfo.getCellData(ds_ContainerBulkInfo.getRowPosition(), "crryinoutDeclarNo");
    var deg = ds_CDMainInfo.getCellData(row, "mainMainAppDeg");


    let win_url = "/ui/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.xml";

    let data = {
        deg : deg,
        docCd : declarAdmitClsCd,
        declarNo : declarNo
    };

    let opts = {
        id : "sd_401_05_04p",	
        popupName : "sd_401_05_04p",
        modal : true,
        type : "browserPopup",
        width : 860,
        height : 580,
        title : ""
    };

    $c.win.openPopup(win_url, opts, data);
};


