scwin.ds_ContainerBulkInfo_onrowpositionchange = function (info) {
	if (info.newRowIndex == 0) return;
	scwin.rowR = info.newRowIndex;
};

scwin.ds_CDMainInfo_onrowpositionchange = function (info) {
	if (info.newRowIndex == 0) return;
	scwin.rowR = info.newRowIndex;
};

scwin.ds_CDMainRegularityTaxInfo_onrowpositionchange = function (info) {
	if (info.newRowIndex == 0) return;

	if (ds_CDMainRegularityTaxInfo.getCellData(info.newRowIndex, "mainMainItem") == '0') {
        gr_CDMainRegularityTaxInfo.setColumnReadOnly("addBl", false);
        gr_CDMainRegularityTaxInfo.setHeaderColor("addBlH", "red");

	} else {
        gr_CDMainRegularityTaxInfo.setColumnReadOnly("addBl", true);
        gr_CDMainRegularityTaxInfo.setHeaderColor("addBlH", "black");    
	}

};



scwin.ds_CDMainRegularityTaxInfo_oncelldatachange = function (info) {
	if (info.colID == "mainMainItem") {
		if (ds_CDMainRegularityTaxInfo.getCellData(info.rowIndex, info.colID) == '0') {
			gr_CDMainRegularityTaxInfo.setColumnReadOnly("addBl", false);
            gr_CDMainRegularityTaxInfo.setHeaderColor("addBlH", "red");    
            gr_CDMainRegularityTaxInfo.setHeaderColor("mainMainBfContH", "black");    
            gr_CDMainRegularityTaxInfo.setHeaderColor("mainMainAfContH", "black");    

		} else {
			gr_CDMainRegularityTaxInfo.setColumnReadOnly("addBl", true);
            gr_CDMainRegularityTaxInfo.setHeaderColor("addBlH", "black");    
            gr_CDMainRegularityTaxInfo.setHeaderColor("mainMainBfContH", "red");    
            gr_CDMainRegularityTaxInfo.setHeaderColor("mainMainAfContH", "red");  
		}
	}
};

