scwin.gr_ContainerBulkInfo_oncellclick = async function (rowIndex, columnIndex, columnId) {


	//if (rowIndex == scwin.rowR) return;

	if (ds_CDMainInfo.getModifiedIndex().length != 0 || ds_CDMainRegularityTaxInfo.getModifiedIndex().length != 0) {
		if (!await $c.win.confirm("변경한 신고정보내역이 취소됩니다. 계속 진행하시겠습니까?")) {
			ds_ContainerBulkInfo.setRowPosition(scwin.rowR);
			return;
		}
	}
  // ds_CDMainRegularityTaxInfo.removeAll();
	scwin.f_Retrieve1(rowIndex);

	scwin.rowR = rowIndex;

};


scwin.gr_CDMainInfo_oncellclick = async function (rowIndex, columnIndex, columnId) {

	// 오류내역 팝업 띄우기
	if (columnId == "sndClsNm") {
		if (!$c.gus.cfIsNull(ds_CDMainInfo.getCellData(rowIndex, "sndClsNm"))) {
			scwin.f_errorPopUp(rowIndex);
		}
	}

	if (rowIndex == scwin.rowM) { 
		return;
	}

	if (ds_CDMainRegularityTaxInfo.getModifiedIndex().length != 0) {
		if (!await $c.win.confirm("변경한 신고정보상세내역이 취소됩니다. 계속 진행하시겠습니까?")) {
			ds_CDMainInfo.setRowPosition(scwin.rowR);
			return;
		}
	};
    scwin.rowM = rowIndex;

    scwin.f_Retrieve2(scwin.rowM);
};

 scwin.callbackOp = function(){

