scwin.f_openPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {


    udc_comCodeWrkPl.cfCommonPopUp(
                                scwin.udc_comCodeWrkPl_callBackFunc,
                                ed_wrkPlCd.getValue(),
                                ed_wrkPlNm.getValue(),
                                "T" //pClose
                                ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
								,null					// Title순서	
								,null					// 보여주는 각 컬럼들의 폭	
								,null					// 컬럼중에서 숨기는	컬럼 지정	
								,null			    	// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
								,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
								,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
								,null					// 윈도우 위치 Y좌표	
								,null					// 윈도우 위치 X좌표
								,null					// 중복체크여부	("F")
								,"T"					// 전체검색허용여부	("F")
								,"작업장,작업장코드,작업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            );

};

scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!await $c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    await $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = await $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openPopUp(disGubun, pVal, '', 'T', 'F');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openPopUp(disGubun, '', pVal, 'T', 'F');
}

