    }
};


//행추가
scwin.f_Addrow1 = function(argGubun) {

    var row = ds_ContainerBulkInfo.getRowPosition();
    if (ds_ContainerBulkInfo.getCellData(row, "sndClsNm") != "접수") {
      $c.gus.cfAlertMsg("해당 세관신고정보의 전송구분이 접수인 상태만 행추가를 할 수 있습니다.");
      return;
    }

    ds_CDMainInfo.insertRow();
    var row1 = ds_CDMainInfo.getRowCount()-1;

    ds_CDMainInfo.setCellData(row1, "wrkClsCd", ds_ContainerBulkInfo.getCellData(row, "wrkClsCd"));
    ds_CDMainInfo.setCellData(row1, "crryinoutClsCd", ds_ContainerBulkInfo.getCellData(row, "crryinoutClsCd"));
    ds_CDMainInfo.setCellData(row1, "wrkPlCd", ds_ContainerBulkInfo.getCellData(row, "wrkPlCd"));
    ds_CDMainInfo.setCellData(row1, "cntrNo", ds_ContainerBulkInfo.getCellData(row, "cntrNo"));
    ds_CDMainInfo.setCellData(row1, "mrn", ds_ContainerBulkInfo.getCellData(row, "mrn"));
    ds_CDMainInfo.setCellData(row1, "msn", ds_ContainerBulkInfo.getCellData(row, "msn"));
    ds_CDMainInfo.setCellData(row1, "hsn", ds_ContainerBulkInfo.getCellData(row, "hsn"));
    ds_CDMainInfo.setCellData(row1, "divsCrryinoutDeg", ds_ContainerBulkInfo.getCellData(row, "divsCrryinoutDeg"));
    ds_CDMainInfo.setCellData(row1, "sndClsCd", "3");

    gr_CDMainInfo.setFocusedCell(row1, "mainMainClsMark", true);
    gr_CDMainInfo.focus();
};


//행추가
scwin.f_Addrow2 = function(argGubun) {

    if (ds_CDMainInfo.getRowCount() == 0) {
      $c.gus.cfAlertMsg("반출입정정 신고정보가 없습니다.");
      return;
    }

    var row1 = ds_CDMainInfo.getRowPosition();
    if (ds_CDMainInfo.getRowStatus(row1) == "C") {
      $c.gus.cfAlertMsg("해당 반출입정정 신고정보는 입력 상태입니다.\n먼저 저장하십시오.");
      return;
    }

    if (ds_CDMainInfo.getRowStatus(row1) == "D") {
      $c.gus.cfAlertMsg("해당 반출입정정 신고정보는 삭제 상태입니다.");
      return;
    }

    if (ds_CDMainInfo.getCellData(row1, "sndClsCd") != 3) {
      $c.gus.cfAlertMsg("해당 반출입정정 신고정보의 전송구분이 미전송인 상태만 행추가를 할 수 있습니다.");
      return;
    }

    ds_CDMainRegularityTaxInfo.insertRow();
    var row2 = ds_CDMainRegularityTaxInfo.getRowCount()-1;

    ds_CDMainRegularityTaxInfo.setCellData(row2, "wrkClsCd", ds_CDMainInfo.getCellData(row1, "wrkClsCd"));
    ds_CDMainRegularityTaxInfo.setCellData(row2, "crryinoutClsCd", ds_CDMainInfo.getCellData(row1, "crryinoutClsCd"));
    ds_CDMainRegularityTaxInfo.setCellData(row2, "wrkPlCd", ds_CDMainInfo.getCellData(row1, "wrkPlCd"));
    ds_CDMainRegularityTaxInfo.setCellData(row2, "cntrNo", ds_CDMainInfo.getCellData(row1, "cntrNo"));
    ds_CDMainRegularityTaxInfo.setCellData(row2, "mrn", ds_CDMainInfo.getCellData(row1, "mrn"));
    ds_CDMainRegularityTaxInfo.setCellData(row2, "msn", ds_CDMainInfo.getCellData(row1, "msn"));
    ds_CDMainRegularityTaxInfo.setCellData(row2, "hsn", ds_CDMainInfo.getCellData(row1, "hsn"));
    ds_CDMainRegularityTaxInfo.setCellData(row2, "divsCrryinoutDeg", ds_CDMainInfo.getCellData(row1, "divsCrryinoutDeg"));
    ds_CDMainRegularityTaxInfo.setCellData(row2, "mainMainAppDeg", ds_CDMainInfo.getCellData(row1, "mainMainAppDeg"));

    if (ds_CDMainInfo.getCellData(row1, "mainMainClsMark") == "0") {
      if (row2 > 1) {
        ds_CDMainRegularityTaxInfo.deleteRow(row2);
        $c.gus.cfAlertMsg("정정항목은 B/L정보만 선택할 수 있습니다.");
      }
      ds_CDMainRegularityTaxInfo.setCellData(row2, "mainMainItem");
    }
     gr_CDMainRegularityTaxInfo.setFocusedCell(row2, 0);
    gr_CDMainInfo.setFocusedCell(row1, "hsn", true);
    gr_CDMainInfo.focus();
};

